CREATE TABLE IF NOT EXISTS backup_records (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, filename TEXT NOT NULL, size_bytes INTEGER NOT NULL, sha256 TEXT NOT NULL DEFAULT '', backup_type TEXT NOT NULL CHECK(backup_type IN ('manual','scheduled_hourly','scheduled_daily','pre_restore')), components TEXT NOT NULL DEFAULT '{}', status TEXT NOT NULL DEFAULT 'completed' CHECK(status IN ('pending','in_progress','completed','failed')), error_message TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')));
CREATE INDEX IF NOT EXISTS idx_backup_records_project ON backup_records(project_id, created_at DESC);
CREATE TABLE IF NOT EXISTS backup_restore_jobs (id TEXT PRIMARY KEY, project_id TEXT NOT NULL REFERENCES projects(id) ON DELETE CASCADE, backup_id TEXT REFERENCES backup_records(id) ON DELETE SET NULL, status TEXT NOT NULL DEFAULT 'validating' CHECK(status IN ('validating','confirmed','applying','completed','failed','rolled_back')), components TEXT NOT NULL DEFAULT '{}', error_message TEXT, started_at TEXT, completed_at TEXT, created_at TEXT NOT NULL DEFAULT (datetime('now')));
